if (intrinsicSize.isUnspecified) {
    // Changed from `PainterModifier`:
    // If AsyncImagePainter has no child painter, do not occupy the max constraints.
    if (!hasBoundedSize ||
        (painter is AsyncImagePainter && painter.state.value.painter == null)
    ) {
        return constraints
    } else {
        return constraints.copy(
            minWidth = constraints.maxWidth,
            minHeight = constraints.maxHeight,
        )
    }
}

if (hasBoundedSize && (hasFixedWidth || hasFixedHeight)) {
    dstWidth = constraints.maxWidth.toFloat()
    dstHeight = constraints.maxHeight.toFloat()
} else {
    val (intrinsicWidth, intrinsicHeight) = intrinsicSize
    dstWidth = when {
        intrinsicWidth.isFinite() -> constraints.constrainWidth(intrinsicWidth)
        else -> constraints.minWidth.toFloat()
    }
    dstHeight = when {
        intrinsicHeight.isFinite() -> constraints.constrainHeight(intrinsicHeight)
        else -> constraints.minHeight.toFloat()
    }
}

if (originalDispatcher == null || originalDispatcher == Dispatchers.Unconfined) {
    return launch(
        context = Dispatchers.Unconfined,
        start = CoroutineStart.UNDISPATCHED,
        block = block,
    )
} else {
    return CoroutineScope(DeferredDispatchCoroutineContext(coroutineContext)).launch(
        context = DeferredDispatchCoroutineDispatcher(originalDispatcher),
        start = CoroutineStart.UNDISPATCHED,
        block = block,
    )
}

if (target is ViewTarget<*>) {
    // CENTER and MATRIX scale types should be decoded at the image's original size.
    val view = target.view
    if (view is ImageView && view.scaleType.let { it == CENTER || it == MATRIX }) {
        return SizeResolver.ORIGINAL
    } else {
        return ViewSizeResolver(view)
    }
} else {
    // Fall back to the image's source dimensions.
    return SizeResolver.ORIGINAL
}

if (manager == null) {
    manager = synchronized(this) {
        // Check again in case the request manager was just set.
        (getTag(R.id.coil3_request_manager) as? ViewTargetRequestManager)
            ?.let { return@synchronized it }

        ViewTargetRequestManager(this).apply {
            addOnAttachStateChangeListener(this)
            setTag(R.id.coil3_request_manager, this)
        }
    }
}

if (topLeft == topRight && topRight == bottomLeft && bottomLeft == bottomRight) {
    drawRoundRect(0f, 0f, outputWidth.toFloat(), outputHeight.toFloat(), topLeft, topLeft, paint)
} else {
    val radii = floatArrayOf(
        topLeft, topLeft,
        topRight, topRight,
        bottomRight, bottomRight,
        bottomLeft, bottomLeft,
    )
    val rect = RectF(0f, 0f, outputWidth.toFloat(), outputHeight.toFloat())
    val path = Path().apply { addRoundRect(rect, radii, Path.Direction.CW) }
    drawPath(path, paint)
}

if (SDK_INT < 24) {
    when (parser.name) {
        "vector" -> {
            return VectorDrawableCompat.createFromXmlInner(
                resources, parser,
                Xml.asAttributeSet(parser), theme,
            )
        }
        "animated-vector" -> {
            return AnimatedVectorDrawableCompat.createFromXmlInner(
                this, resources,
                parser, Xml.asAttributeSet(parser), theme,
            )
        }
    }
}

if (checkFileDescriptors()) {
    decodesSinceLastFileDescriptorCheck = 0
    lastFileDescriptorCheckTimestamp = SystemClock.uptimeMillis()

    val numUsedFileDescriptors = fileDescriptorList.list().orEmpty().count()
    hasAvailableFileDescriptors = numUsedFileDescriptors < FILE_DESCRIPTOR_LIMIT
    if (!hasAvailableFileDescriptors) {
        logger?.log(TAG, Logger.Level.Warn) {
            "Unable to allocate more hardware bitmaps. " +
                "Number of used file descriptors: $numUsedFileDescriptors"
        }
    }
}

try {
    suspendCancellableCoroutine { continuation ->
        observer = object : DefaultLifecycleObserver {
            override fun onStart(owner: LifecycleOwner) {
                continuation.resume(Unit)
            }
        }
        addObserver(observer)
    }
} finally {
    // 'observer' will always be null if this method is marked as 'inline'.
    observer?.let(::removeObserver)
}

when {
    level >= TRIM_MEMORY_BACKGROUND -> {
        // The app is in the background and is in the queue to be killed.
        imageLoader.memoryCache?.clear()
    }
    level >= TRIM_MEMORY_UI_HIDDEN -> {
        // The app is in the background.
        activityCallbacks.register(imageLoader.options.application)
    }
    level >= TRIM_MEMORY_RUNNING_LOW -> {
        // The app is in the foreground, but is running low on memory.
        imageLoader.memoryCache?.apply { trimToSize(size / 2) }
    }
}

if (MAGIC != magic ||
                VERSION != version ||
                appVersion.toString() != appVersionString ||
                valueCount.toString() != valueCountString ||
                blank.isNotEmpty()
            ) {
                throw IOException(
                    "unexpected journal header: " +
                    "[$magic, $version, $appVersionString, $valueCountString, $blank]",
                )
            }

when {
    secondSpace != -1 && firstSpace == CLEAN.length && line.startsWith(CLEAN) -> {
        val parts = line.substring(secondSpace + 1).split(' ')
        entry.readable = true
        entry.currentEditor = null
        entry.setLengths(parts)
    }
    secondSpace == -1 && firstSpace == DIRTY.length && line.startsWith(DIRTY) -> {
        entry.currentEditor = Editor(entry)
    }
    secondSpace == -1 && firstSpace == READ.length && line.startsWith(READ) -> {
        // This work was already done by calling lruEntries.get().
    }
    else -> throw IOException("unexpected journal line: $line")
}

while (iterator.hasNext()) {
    val entry = iterator.next()
    if (entry.currentEditor == null) {
        for (i in 0 until valueCount) {
            size += entry.lengths[i]
        }
    } else {
        entry.currentEditor = null
        for (i in 0 until valueCount) {
            fileSystem.delete(entry.cleanFiles[i])
            fileSystem.delete(entry.dirtyFiles[i])
        }
        iterator.remove()
    }
}

while (true) {
    val pair = components.newDecoder(fetchResult, options, imageLoader, searchIndex)
    checkNotNull(pair) { "Unable to create a decoder that supports: $mappedData" }
    val decoder = pair.first
    searchIndex = pair.second + 1

    eventListener.decodeStart(request, decoder, options)
    val result = decoder.decode()
    eventListener.decodeEnd(request, decoder, options, result)

    if (result != null) {
        decodeResult = result
        break
    }
}

if (cacheKeySize != null) {
    if (cacheKeySize == size.toString()) {
        return true
    } else {
        logger?.log(TAG, Logger.Level.Debug) {
            "${request.data}: Memory cached image's size " +
                "($cacheKeySize) does not exactly match the target size " +
                "($size)."
        }
        return false
    }
}

if (values.isEmpty()) {
    values += newValue
} else {
    for (index in values.indices) {
        val value = values[index]
        if (size >= value.size) {
            if (value.image.get() === image) {
                values[index] = newValue
            } else {
                values.add(index, newValue)
            }
            break
        }
    }
}

if (!needsExecuteOnMainDispatcher(request)) {
    // Fast path: skip dispatching.
    return execute(request, REQUEST_TYPE_EXECUTE)
} else {
    // Slow path: dispatch to the main thread.
    return coroutineScope {
        // Start executing the request on the main thread.
        val job = async(options.mainCoroutineContextLazy.value) {
            execute(request, REQUEST_TYPE_EXECUTE)
        }

        // Update the current request attached to the view and await the result.
        getDisposable(request, job).job.await()
    }
}

if (duration == 0) {
    invalidate = false
    time = 0
} else {
    if (isRunning) {
        frameTimeMillis = SystemClock.uptimeMillis()
    }
    val elapsedTime = (frameTimeMillis - startTimeMillis).toInt()
    loopIteration = elapsedTime / duration
    invalidate = repeatCount == REPEAT_INFINITE || loopIteration <= repeatCount
    time = if (invalidate) elapsedTime - loopIteration * duration else duration
}

if (isSoftwareScalingEnabled) {
    hardwareScale = 1f
    hardwareDx = 0f
    hardwareDy = 0f
} else {
    hardwareScale = DecodeUtils.computeSizeMultiplier(
        srcWidth = bitmapWidth,
        srcHeight = bitmapHeight,
        dstWidth = boundsWidth,
        dstHeight = boundsHeight,
        scale = scale,
        maxSize = Size.ORIGINAL,
    ).toFloat()
    hardwareDx = bounds.left + (boundsWidth - hardwareScale * bitmapWidth) / 2
    hardwareDy = bounds.top + (boundsHeight - hardwareScale * bitmapHeight) / 2
}

if (!responseCaching.noCache && ageMillis + minFreshMillis < freshMillis + maxStaleMillis) {
    val headersBuilder = cacheResponse.headers.newBuilder()
    if (ageMillis + minFreshMillis >= freshMillis) {
        headersBuilder.add("Warning", "110 HttpURLConnection \"Response is stale\"")
    }
    val oneDayMillis = 24 * 60 * 60 * 1000L
    if (ageMillis > oneDayMillis && isFreshnessLifetimeHeuristic()) {
        headersBuilder.add("Warning", "113 HttpURLConnection \"Heuristic expiration\"")
    }
    return ReadResult(cacheResponse.copy(headers = headersBuilder.build()))
}

try {
    fileSystem.write(editor.metadata) {
        CacheNetworkResponse.writeTo(modifiedNetworkResponse, this)
    }
    modifiedNetworkResponse.body?.writeTo(fileSystem, editor.data)
    return editor.commitAndOpenSnapshot()
} catch (e: Exception) {
    editor.abortQuietly()
    networkResponse.body?.closeQuietly()
    modifiedNetworkResponse.body?.closeQuietly()
    throw e
}

if (useParentActivityScope){
    val activityScope: Scope? = (activity as? AndroidScopeComponent)?.scope
    if (activityScope != null) {
        scope.logger.debug("Link to parent activity scope: '${activityScope.id}'")
        scope.linkTo(activityScope)
    } else {
        scope.logger.debug("Fragment '$this' can't be linked to parent activity scope. No Parent Activity Scope found.")
    }
}

if (KoinPlatform.getKoinOrNull() == null && koinApplication != null){
    try {
        koin = startKoin(koinApplication).koin
        koin!!.logger.debug("$this -> attach Koin instance $koin")
    } catch (e: Exception) {
        error("Can't start Koin from Compose context - $e")
    }
} else if (KoinPlatform.getKoinOrNull() != null) {
    koin = KoinPlatform.getKoin()
    koin!!.logger.debug("$this -> re-attach Koin instance $koin")
} else {
    error("Can't start Koin context, no koinApplication argument found nor existing context")
}

if (isEmpty()) null
    else {
        runCatching {
            MutableCreationExtras().also { extras ->
                extras[DEFAULT_ARGS_KEY] = this@toExtras
                extras[VIEW_MODEL_STORE_OWNER_KEY] = viewModelStoreOwner
                extras[SAVED_STATE_REGISTRY_OWNER_KEY] = viewModelStoreOwner as SavedStateRegistryOwner
            }
        }.getOrNull()
    }

if (!koin.optionRegistry.hasViewModelScopeFactory()){
    scope.getWithParameters(kClass, qualifier, androidParams)
} else {
    val scopeId = getViewModelScopeId(modelClass)
    val vmScope = koin.createScope(scopeId, TypeQualifier(modelClass), null, ViewModelScopeArchetype)
    val vm : T = vmScope.getWithParameters(kClass, qualifier, androidParams)
    vm.addCloseable(ViewModelScopeAutoCloseable(scopeId,koin))
    vm
}

if (!allowOverride) {
    throwOverrideError(factory, mapping)
} else if (logWarning) {
    _koin.logger.warn("(+) override index '$mapping' -> '${factory.beanDefinition}'")
    // remove previous eager isntance too
    val existingFactory = eagerInstances.values.firstOrNull { it.beanDefinition == factory.beanDefinition }
    if (existingFactory != null) {
        eagerInstances.remove(factory.beanDefinition.hashCode())
    }
}

try {
    get(clazz, qualifier, parameters)
} catch (e: ClosedScopeException) {
    _koin.logger.debug("* Scope closed - no instance found for ${clazz.getFullName()} on scope ${toString()}")
    null
} catch (e: NoDefinitionFoundException) {
    _koin.logger.debug("* No instance found for type '${clazz.getFullName()}' on scope '${toString()}'")
    null
} catch (e: MissingScopeValueException) {
    _koin.logger.debug("* No Scoped value found for type '${clazz.getFullName()}' on scope '${toString()}'")
    null
}

try {
    getWithParameters(ctx.clazz, ctx.qualifier, ctx.parameters)
} catch (e: ClosedScopeException) {
    _koin.logger.debug("* Scope closed - no instance found for ${ctx.clazz.getFullName()} on scope ${toString()}")
    null
} catch (e: NoDefinitionFoundException) {
    _koin.logger.debug("* No instance found for type '${ctx.clazz.getFullName()}' on scope '${toString()}'")
    null
}

when {
    cur === CLOSE_HANDLER_CLOSED -> {
        // Try to update the state from `CLOSED` to `INVOKED`.
        // This is crucial to guarantee that at most one handler can be called.
        // On success, invoke the handler and finish.
        if (closeHandler.compareAndSet(CLOSE_HANDLER_CLOSED, CLOSE_HANDLER_INVOKED)) {
            handler(closeCause)
            return
        }
    }
    cur === CLOSE_HANDLER_INVOKED -> error("Another handler was already registered and successfully invoked")
    else -> error("Another handler is already registered: $cur")
}

when (this) {
    is SendBroadcast -> cont.resume(false)
    is CancellableContinuation<*> -> resumeWithException(if (receiver) receiveException else sendException)
    is ReceiveCatching<*> -> cont.resume(closed(closeCause))
    is BufferedChannel<*>.BufferedChannelIterator -> tryResumeHasNextOnClosedChannel()
    is SelectInstance<*> -> trySelect(this@BufferedChannel, CHANNEL_CLOSED)
    else -> error("Unexpected waiter: $this")
}
